@push('scripts')<script>function editUser(button){const data=button.dataset;const form=document.getElementById('user-edit-form');form.action=`{{url('/users')}}/${data.id}`;document.getElementById('user-name').value=data.name;document.getElementById('user-email').value=data.email;document.getElementById('user-role').value=data.role;document.getElementById('user-active').checked=data.active==='1';document.getElementById('user-dialog').showModal()}</script>@endpush
